"use client";

import { useState, useEffectEvent } from "react";

export interface UseControllableStateOptions<T> {
  value?: T;
  defaultValue: T;
  onChange?: (value: T) => void;
}

export function useControllableState<T>({
  value: controlledValue,
  defaultValue,
  onChange,
}: UseControllableStateOptions<T>) {
  const [internal, setInternal] = useState(defaultValue);

  const current = controlledValue !== undefined ? controlledValue : internal;

  const setValue = useEffectEvent((next: T | ((prev: T) => T)) => {
    if (controlledValue !== undefined) {
      const resolved = typeof next === "function"
        ? (next as (prev: T) => T)(current)
        : next;
      onChange?.(resolved);
    } else {
      setInternal((prev) => {
        const resolved = typeof next === "function"
          ? (next as (prev: T) => T)(prev)
          : next;
        onChange?.(resolved);
        return resolved;
      });
    }
  });

  return [current, setValue, controlledValue !== undefined] as const;
}

"use client";

import { useEffect, useEffectEvent, useRef, useState } from "react";

export type ActiveHeadingActivation = "top-line" | "viewport-center" | (number & {});

export interface UseActiveHeadingOptions {
  ids: string[];
  containerId?: string;
  /** @default "top-line" */
  activation?: ActiveHeadingActivation;
  topOffset?: number;
  scrollOffset?: number;
  bottomMargin?: number;
  threshold?: number;
  bottomLock?: boolean;
  enabled?: boolean;
  settleDelay?: number;
  /** Watch for DOM changes via MutationObserver. Disable for static content. @default true */
  observe?: boolean;
}

export interface UseActiveHeadingReturn {
  activeId: string | null;
  scrollTo: (id: string) => void;
}

function getContainer(id: string | undefined): HTMLElement | null {
  if (!id) return null;
  const el = document.getElementById(id);
  return el instanceof HTMLElement ? el : null;
}

function getViewportMetrics(container: HTMLElement | null) {
  if (container) {
    return {
      top: container.getBoundingClientRect().top,
      height: container.clientHeight,
      scrollTop: container.scrollTop,
      scrollHeight: container.scrollHeight,
    };
  }

  const root = document.documentElement;
  const body = document.body;
  const scrollTop = window.scrollY || root.scrollTop || body?.scrollTop || 0;
  const scrollHeight = Math.max(root.scrollHeight, body?.scrollHeight ?? 0);

  return {
    top: 0,
    height: window.innerHeight,
    scrollTop,
    scrollHeight,
  };
}

function findLastAbove(elements: HTMLElement[], line: number, thresholdRatio = 0): string | null {
  for (let i = elements.length - 1; i >= 0; i--) {
    const rect = elements[i]!.getBoundingClientRect();
    if (rect.top + rect.height * thresholdRatio <= line) return elements[i]!.id;
  }
  return null;
}

function resolveScrollBehavior(): ScrollBehavior {
  return typeof window.matchMedia === "function" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches
    ? "auto"
    : "smooth";
}

function resolveActivationLine(
  top: number,
  height: number,
  activation: ActiveHeadingActivation,
  topOffset: number,
): number {
  if (typeof activation === "number") {
    return top + height * Math.max(0, Math.min(1, activation));
  }
  if (activation === "viewport-center") return top + height / 2;
  return top + topOffset;
}

export function useActiveHeading({
  ids,
  containerId,
  activation = "top-line",
  topOffset = 96,
  scrollOffset = topOffset,
  bottomMargin = 0,
  threshold = 0,
  bottomLock = true,
  enabled = true,
  settleDelay = 150,
  observe = true,
}: UseActiveHeadingOptions): UseActiveHeadingReturn {
  const idsKey = ids.join("\0");
  const [activeId, setActiveId] = useState<string | null>(ids[0] ?? null);
  const scrollingToRef = useRef<string | null>(null);
  const settleTimerRef = useRef<number>(0);

  const update = useEffectEvent((): void => {
    if (scrollingToRef.current !== null) return;

    const container = getContainer(containerId);
    const elements = ids
      .map((id) => document.getElementById(id))
      .filter((el): el is HTMLElement => el instanceof HTMLElement);

    if (elements.length === 0) {
      setActiveId(ids[0] ?? null);
      return;
    }

    const { top, height, scrollTop, scrollHeight } = getViewportMetrics(container);
    const bottomMarginPx = Math.max(0, bottomMargin) * height;

    if (bottomLock && scrollTop + height >= scrollHeight - 2 - bottomMarginPx) {
      setActiveId(elements[elements.length - 1]?.id ?? null);
      return;
    }

    const activationLine = resolveActivationLine(top, height, activation, topOffset);
    const t = Math.max(0, Math.min(1, threshold));
    let next = findLastAbove(elements, activationLine, t) ?? elements[0]?.id ?? null;

    if (next && elements.length > 1) {
      const pickedEl = document.getElementById(next);
      if (pickedEl && pickedEl.getBoundingClientRect().bottom < top) {
        next = findLastAbove(elements, top + height * 0.5) ?? next;
      }
    }

    setActiveId(next);
  });

  useEffect(() => {
    if (!enabled || ids.length === 0) {
      setActiveId(null);
      return;
    }

    setActiveId(ids[0] ?? null);

    const container = getContainer(containerId);
    const scrollTarget: EventTarget = container ?? window;
    const hasScrollEnd = "onscrollend" in window;
    let frame = 0;

    const scheduleUpdate = (): void => {
      if (scrollingToRef.current !== null) {
        if (!hasScrollEnd) {
          if (settleTimerRef.current !== 0) window.clearTimeout(settleTimerRef.current);
          settleTimerRef.current = window.setTimeout(() => {
            settleTimerRef.current = 0;
            scrollingToRef.current = null;
            update();
          }, settleDelay);
        }
        return;
      }

      if (frame !== 0) return;
      frame = window.requestAnimationFrame(() => {
        frame = 0;
        update();
      });
    };

    const handleScrollEnd = (): void => {
      if (scrollingToRef.current === null) return;
      scrollingToRef.current = null;
      update();
    };

    scrollTarget.addEventListener("scroll", scheduleUpdate, { passive: true });
    window.addEventListener("resize", scheduleUpdate);
    if (hasScrollEnd) scrollTarget.addEventListener("scrollend", handleScrollEnd);

    let mutationObs: MutationObserver | null = null;
    if (observe) {
      mutationObs = new MutationObserver(scheduleUpdate);
      mutationObs.observe(container ?? document.body, { childList: true, subtree: true });
    }

    scheduleUpdate();

    return () => {
      scrollTarget.removeEventListener("scroll", scheduleUpdate);
      window.removeEventListener("resize", scheduleUpdate);
      if (hasScrollEnd) scrollTarget.removeEventListener("scrollend", handleScrollEnd);
      mutationObs?.disconnect();
      if (frame !== 0) window.cancelAnimationFrame(frame);
      if (settleTimerRef.current !== 0) window.clearTimeout(settleTimerRef.current);
    };
  }, [idsKey, containerId, enabled, settleDelay, observe]);

  const scrollTo = useEffectEvent((id: string) => {
    const heading = document.getElementById(id);
    if (!(heading instanceof HTMLElement)) return;

    scrollingToRef.current = id;
    setActiveId(id);

    const container = getContainer(containerId);
    const behavior = resolveScrollBehavior();

    if (container) {
      const containerRect = container.getBoundingClientRect();
      const headingRect = heading.getBoundingClientRect();
      const relativeTop = headingRect.top - containerRect.top + container.scrollTop;
      container.scrollTo({ top: Math.max(0, relativeTop - scrollOffset), behavior });
    } else {
      window.scrollTo({
        top: Math.max(0, window.scrollY + heading.getBoundingClientRect().top - scrollOffset),
        behavior,
      });
    }
  });

  return { activeId, scrollTo };
}

"use client";

import { useLayoutEffect, useRef, useState, useEffectEvent } from "react";

export type OverflowDirection = "horizontal" | "vertical" | "both";

export function useOverflow<T extends HTMLElement = HTMLElement>(
  direction: OverflowDirection = "horizontal"
): { ref: React.RefObject<T | null>; isOverflowing: boolean } {
  const ref = useRef<T | null>(null);
  const [isOverflowing, setIsOverflowing] = useState(false);

  const check = useEffectEvent(() => {
    const el = ref.current;
    if (!el) return;

    const h = el.scrollWidth > el.clientWidth;
    const v = el.scrollHeight > el.clientHeight;

    setIsOverflowing({ horizontal: h, vertical: v, both: h || v }[direction]);
  });

  useLayoutEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new ResizeObserver(check);
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  useLayoutEffect(() => {
    check();
  }, [direction]);

  return { ref, isOverflowing };
}

"use client";

import { useLayoutEffect, useRef, useState, useEffectEvent } from "react";

export interface UseOverflowItemsOptions {
  itemCount: number;
  onVisibleCountChange?: (count: number) => void;
}

export interface UseOverflowItemsReturn {
  ref: React.RefObject<HTMLDivElement | null>;
  visibleCount: number;
  overflowCount: number;
}

export function computeVisibleCount(
  itemWidths: number[],
  containerWidth: number,
  gap: number,
  indicatorWidth: number,
): number {
  let usedWidth = 0;
  for (let i = 0; i < itemWidths.length; i++) {
    const nextWidth = usedWidth + itemWidths[i]! + (i > 0 ? gap : 0);
    const remaining = itemWidths.length - (i + 1);
    const reserve = remaining > 0 ? indicatorWidth + gap : 0;
    if (nextWidth + reserve > containerWidth && i > 0) return i;
    usedWidth = nextWidth;
  }
  return itemWidths.length;
}

export function useOverflowItems({
  itemCount,
  onVisibleCountChange,
}: UseOverflowItemsOptions): UseOverflowItemsReturn {
  const ref = useRef<HTMLDivElement>(null);
  const [visibleCount, setVisibleCount] = useState(itemCount);

  const onRecalculate = useEffectEvent(() => {
    const container = ref.current;
    if (!container) return;

    const children = Array.from(container.children) as HTMLElement[];
    if (children.length === 0) return;

    const containerWidth = container.offsetWidth;
    const gap = parseFloat(getComputedStyle(container).gap) || 0;

    const items = children.slice(0, itemCount);
    const indicator = children[itemCount];

    const itemWidths = items.map(el => el.offsetWidth);
    const indicatorWidth = indicator ? indicator.offsetWidth : 0;

    const count = computeVisibleCount(itemWidths, containerWidth, gap, indicatorWidth);

    if (count !== visibleCount) {
      setVisibleCount(count);
      onVisibleCountChange?.(count);
    }
  });

  useLayoutEffect(() => {
    const container = ref.current;
    if (!container) return;

    const observer = new ResizeObserver(onRecalculate);
    observer.observe(container);
    return () => observer.disconnect();
  }, []);

  useLayoutEffect(() => {
    onRecalculate();
  }, [itemCount]);

  return {
    ref,
    visibleCount,
    overflowCount: itemCount - visibleCount,
  };
}

"use client";

import { useEffect, useEffectEvent, type RefObject } from "react";

export function useOutsideClick(
  ref: RefObject<HTMLElement | null>,
  handler: () => void,
  enabled: boolean = true,
  excludeRefs?: ReadonlyArray<RefObject<HTMLElement | null>>,
): void {
  const onOutsideClick = useEffectEvent((target: Node) => {
    if (excludeRefs?.some(r => r.current?.contains(target))) return;
    handler();
  });

  useEffect(() => {
    if (!enabled) return;

    const handleClick = (e: MouseEvent) => {
      if (!(e.target instanceof Node)) return;
      if (ref.current && !ref.current.contains(e.target)) {
        onOutsideClick(e.target);
      }
    };

    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [enabled]);
}

"use client";

import { useState, useEffectEvent, type AnimationEvent, type RefObject } from "react";

type Phase = "hidden" | "open" | "closing";

export interface UsePresenceOptions {
  open: boolean;
  ref?: RefObject<HTMLElement | null>;
}

export function usePresence({ open, ref }: UsePresenceOptions) {
  const [phase, setPhase] = useState<Phase>(open ? "open" : "hidden");

  // Intentional "adjust state during render" pattern supported by React 19:
  // synchronously sync phase with the `open` prop before commit.
  if (open && phase !== "open") {
    setPhase("open");
  }

  if (!open && phase === "open") {
    setPhase("closing");
  }

  const onAnimationEnd = useEffectEvent((e: AnimationEvent) => {
    if (ref && e.target !== ref.current) return;
    if (phase === "closing") {
      setPhase("hidden");
    }
  });

  return { present: phase !== "hidden", exiting: phase === "closing", onAnimationEnd } as const;
}

"use client";

import { useLayoutEffect, useRef, useState, useEffectEvent } from "react";

export type FloatingSide = "top" | "bottom" | "left" | "right";
export type FloatingAlign = "start" | "center" | "end";
export type FloatingPlacement = `${FloatingSide}` | `${FloatingSide}-${FloatingAlign}`;

export interface UseFloatingPositionOptions {
  triggerRef: React.RefObject<HTMLElement | null>;
  open: boolean;
  side?: FloatingSide;
  align?: FloatingAlign;
  sideOffset?: number;
  alignOffset?: number;
  collisionPadding?: number;
  avoidCollisions?: boolean;
}

export interface FloatingPosition {
  x: number;
  y: number;
  side: FloatingSide;
  align: FloatingAlign;
}

export interface UseFloatingPositionReturn {
  position: FloatingPosition | null;
  contentRef: React.RefObject<HTMLDivElement | null>;
}

const OPPOSITE_SIDE: Record<FloatingSide, FloatingSide> = {
  top: "bottom",
  bottom: "top",
  left: "right",
  right: "left",
};

const CROSS_AXIS_SIDES: Record<FloatingSide, [FloatingSide, FloatingSide]> = {
  top: ["left", "right"],
  bottom: ["left", "right"],
  left: ["top", "bottom"],
  right: ["top", "bottom"],
};

interface Viewport { width: number; height: number }

export function computePosition(
  triggerRect: DOMRect,
  contentRect: DOMRect,
  side: FloatingSide,
  align: FloatingAlign,
  sideOffset: number,
  alignOffset: number,
): { x: number; y: number } {
  let x = 0;
  let y = 0;

  switch (side) {
    case "top":
      y = triggerRect.top - contentRect.height - sideOffset;
      break;
    case "bottom":
      y = triggerRect.bottom + sideOffset;
      break;
    case "left":
      x = triggerRect.left - contentRect.width - sideOffset;
      break;
    case "right":
      x = triggerRect.right + sideOffset;
      break;
  }

  const isVertical = side === "top" || side === "bottom";

  if (isVertical) {
    switch (align) {
      case "start":
        x = triggerRect.left + alignOffset;
        break;
      case "center":
        x = triggerRect.left + triggerRect.width / 2 - contentRect.width / 2 + alignOffset;
        break;
      case "end":
        x = triggerRect.right - contentRect.width - alignOffset;
        break;
    }
  } else {
    switch (align) {
      case "start":
        y = triggerRect.top + alignOffset;
        break;
      case "center":
        y = triggerRect.top + triggerRect.height / 2 - contentRect.height / 2 + alignOffset;
        break;
      case "end":
        y = triggerRect.bottom - contentRect.height - alignOffset;
        break;
    }
  }

  return { x, y };
}

export function wouldOverflow(
  x: number,
  y: number,
  contentRect: DOMRect,
  padding: number,
  vp: Viewport,
): boolean {
  return (
    x < padding ||
    y < padding ||
    x + contentRect.width > vp.width - padding ||
    y + contentRect.height > vp.height - padding
  );
}

export function shift(
  x: number,
  y: number,
  contentRect: DOMRect,
  padding: number,
  vp: Viewport,
): { x: number; y: number } {
  return {
    x: Math.max(padding, Math.min(x, vp.width - contentRect.width - padding)),
    y: Math.max(padding, Math.min(y, vp.height - contentRect.height - padding)),
  };
}

export function resolveCollisionPosition(
  triggerRect: DOMRect,
  contentRect: DOMRect,
  preferredSide: FloatingSide,
  preferredAlign: FloatingAlign,
  sideOffset: number,
  alignOffset: number,
  collisionPadding: number,
  vp: Viewport,
): { x: number; y: number; side: FloatingSide } {
  const candidates: FloatingSide[] = [
    preferredSide,
    OPPOSITE_SIDE[preferredSide],
    ...CROSS_AXIS_SIDES[preferredSide],
  ];

  for (const side of candidates) {
    const pos = computePosition(triggerRect, contentRect, side, preferredAlign, sideOffset, alignOffset);
    if (!wouldOverflow(pos.x, pos.y, contentRect, collisionPadding, vp)) {
      return { ...pos, side };
    }
  }

  const fallback = computePosition(triggerRect, contentRect, preferredSide, preferredAlign, sideOffset, alignOffset);
  return { ...fallback, side: preferredSide };
}

export function useFloatingPosition({
  triggerRef,
  open,
  side: preferredSide = "top",
  align: preferredAlign = "center",
  sideOffset = 6,
  alignOffset = 0,
  collisionPadding = 8,
  avoidCollisions = true,
}: UseFloatingPositionOptions): UseFloatingPositionReturn {
  const [position, setPosition] = useState<FloatingPosition | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);

  const update = useEffectEvent(() => {
    const trigger = triggerRef.current;
    const content = contentRef.current;
    if (!trigger || !content) return;

    const triggerRect = trigger.getBoundingClientRect();
    const contentRect = content.getBoundingClientRect();
    const vp: Viewport = { width: window.innerWidth, height: window.innerHeight };

    const { x: resolvedX, y: resolvedY, side: finalSide } = avoidCollisions
      ? resolveCollisionPosition(triggerRect, contentRect, preferredSide, preferredAlign, sideOffset, alignOffset, collisionPadding, vp)
      : { ...computePosition(triggerRect, contentRect, preferredSide, preferredAlign, sideOffset, alignOffset), side: preferredSide };

    const pos = avoidCollisions
      ? shift(resolvedX, resolvedY, contentRect, collisionPadding, vp)
      : { x: resolvedX, y: resolvedY };

    setPosition({ x: pos.x, y: pos.y, side: finalSide, align: preferredAlign });
  });

  useLayoutEffect(() => {
    if (!open) {
      setPosition(null);
      return;
    }

    update();

    const trigger = triggerRef.current;
    const content = contentRef.current;
    if (!trigger || !content) return;

    const observer = new ResizeObserver(update);
    observer.observe(trigger);
    observer.observe(content);

    const scrollParents: Element[] = [];
    let el: Element | null = trigger;
    while (el) {
      if (el.scrollHeight > el.clientHeight || el.scrollWidth > el.clientWidth) {
        scrollParents.push(el);
      }
      el = el.parentElement;
    }

    for (const parent of scrollParents) {
      parent.addEventListener("scroll", update, { passive: true });
    }
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update);

    return () => {
      observer.disconnect();
      for (const parent of scrollParents) {
        parent.removeEventListener("scroll", update);
      }
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [open]);

  return { position, contentRef };
}

"use client";

import { useEffect, useRef, type KeyboardEvent, type Ref } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useControllableState } from "@/hooks/use-controllable-state";
import { composeRefs } from "@/lib/compose-refs";

export interface UseListboxOptions {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  highlightedId?: string | null;
  defaultHighlightedId?: string | null;
  onSelect?: (id: string) => void;
  onHighlightChange?: (id: string) => void;
  wrap?: boolean;
  idPrefix: string;
  onKeyDown?: (event: KeyboardEvent) => void;
  role?: "listbox" | "menu";
  itemRole?: "option" | "menuitem";
  typeahead?: boolean;
}

export interface UseListboxReturn {
  selectedId: string | null;
  highlightedId: string | null;
  handleItemHighlight: (id: string) => void;
  handleItemActivate: (id: string) => void;
  getContainerProps: (ref?: Ref<HTMLDivElement>) => {
    ref: ReturnType<typeof composeRefs<HTMLDivElement>>;
    role: string;
    tabIndex: 0;
    "aria-activedescendant": string | undefined;
    onKeyDown: (e: KeyboardEvent<HTMLDivElement>) => void;
  };
}

const TYPEAHEAD_RESET_MS = 500;

function getAccessibleText(el: HTMLElement): string {
  let text = "";
  for (const node of el.childNodes) {
    if (node.nodeType === Node.TEXT_NODE) {
      text += node.textContent;
    } else if (node.nodeType === Node.ELEMENT_NODE) {
      const child = node as HTMLElement;
      if (child.getAttribute("aria-hidden") !== "true") {
        text += getAccessibleText(child);
      }
    }
  }
  return text;
}

export function useListbox({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlightedId: controlledHighlightedId,
  defaultHighlightedId = null,
  onSelect,
  onHighlightChange,
  wrap = true,
  idPrefix,
  onKeyDown,
  role: containerRole = "listbox",
  itemRole = "option",
  typeahead = false,
}: UseListboxOptions): UseListboxReturn {
  const containerRef = useRef<HTMLDivElement>(null);
  const typeaheadBuffer = useRef("");
  const typeaheadTimer = useRef<number>(0);

  useEffect(() => () => clearTimeout(typeaheadTimer.current), []);

  const [selectedId, setSelectedId] = useControllableState<string | null>({
    value: controlledSelectedId,
    defaultValue: defaultSelectedId,
    onChange: (next) => {
      if (next !== null) onSelect?.(next);
    },
  });

  const [highlightedId, setHighlightedId] = useControllableState<string | null>({
    value: controlledHighlightedId,
    defaultValue: defaultHighlightedId,
    onChange: (next) => {
      if (next !== null) onHighlightChange?.(next);
    },
  });

  const handleItemActivate = (next: string) => {
    setSelectedId(next);
    setHighlightedId(next);
  };

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: itemRole,
    wrap,
    value: highlightedId ?? undefined,
    onValueChange: setHighlightedId,
    onEnter: handleItemActivate,
    onSelect: handleItemActivate,
  });

  const handleTypeahead = (key: string): void => {
    if (!typeahead || key.length !== 1 || key === " ") return;
    clearTimeout(typeaheadTimer.current);
    typeaheadBuffer.current += key;
    typeaheadTimer.current = window.setTimeout(() => {
      typeaheadBuffer.current = "";
    }, TYPEAHEAD_RESET_MS);

    const query = typeaheadBuffer.current.toLowerCase();
    const items = containerRef.current?.querySelectorAll<HTMLElement>(
      `[role="${itemRole}"]:not([aria-disabled="true"])`,
    );
    if (!items) return;
    for (const item of items) {
      const label = getAccessibleText(item).trim().toLowerCase();
      if (label.startsWith(query) && item.dataset.value) {
        setHighlightedId(item.dataset.value);
        item.scrollIntoView?.({ block: "nearest" });
        break;
      }
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) {
      navKeyDown(e);
      if (!e.ctrlKey && !e.metaKey && !e.altKey) handleTypeahead(e.key);
    }
  };

  const activeDescendant = highlightedId ?? selectedId;

  const getContainerProps = (ref?: Ref<HTMLDivElement>) => ({
    ref: composeRefs(containerRef, ref),
    role: containerRole,
    tabIndex: 0 as const,
    "aria-activedescendant": activeDescendant
      ? `${idPrefix}-${activeDescendant}`
      : undefined,
    onKeyDown: handleKeyDown,
  });

  return {
    selectedId,
    highlightedId,
    handleItemHighlight: setHighlightedId,
    handleItemActivate,
    getContainerProps,
  };
}
